 78→export async function requireAuthorizedContext(
 79→  options: ToolExecutionOptions,
 80→  action: AuthorityAction,
 81→  deps: { surreal: Surreal },
 82→): Promise<AuthorizedContext> {
 83→  const context = requireToolContext(options);
 84→
 85→  // Human-present web sessions bypass authority (human IS the authority)
 86→  if (context.humanPresent) {
 87→    return { context, permission: "auto" };
 88→  }
 89→
 90→  const agentType: AgentType =
 91→    context.agentType ?? ACTOR_DEFAULT_AGENT_TYPE[context.actor] ?? "code_agent";
 92→
 93→  const permission = await checkAuthority({
 94→    surreal: deps.surreal,
 95→    agentType,
 96→    action,
 97→    workspaceRecord: context.workspaceRecord,
 98→  });
 99→
100→  if (permission === "blocked") {
101→    throw new AuthorityError("blocked", action, agentType);
102→  }
103→
104→  if (permission === "propose") {
105→    throw new AuthorityError("propose", action, agentType);
106→  }
107→
108→  // "auto" or "provisional" — caller proceeds (may mark output as provisional)
109→  return { context, permission };
110→}
