112→export function checkAuthorityOrError(
113→  permission: AuthorityPermission,
114→  action: AuthorityAction,
115→  agentType: AgentType,
116→): Response | undefined {
117→  if (permission === "blocked") {
118→    return jsonError(`${agentType} is not authorized for action: ${action}`, 403);
119→  }
120→  if (permission === "propose") {
121→    return jsonError(
122→      `${agentType} can only propose ${action} — requires human approval`,
123→      403,
124→    );
125→  }
126→  return undefined;
127→}
