  task: { id: string; title: string; description?: string; status: string; category?: string };
  subtasks: { id: string; title: string; status: string }[];
  parent_feature?: { id: string; name: string; description?: string };
  sibling_tasks: { id: string; title: string; status: string; source_session?: string }[];
  dependencies: { id: string; title: string; status: string }[];
  related_sessions: { id: string; agent: string; ended_at: string; summary: string }[];
};

export type DecisionContext = {
  id: string;
  summary: string;
  status: string;
  rationale?: string;
  decided_at?: string;
  category?: string;
  priority?: string;
};

export type TaskContext = {
  id: string;
  title: string;
  status: string;
  priority?: string;
  category?: string;
  source_session?: string;
};

export type QuestionContext = {
  id: string;
  text: string;
  status: string;
  context?: string;
  priority?: string;
};

export type RecentChangeContext = {
  entity_type: string;
  entity_name: string;
  change_type: string;
  changed_at: string;
};

export type ObservationContext = {
  id: string;
  text: string;
  severity: string;
  status: string;
  category?: string;
  observation_type?: string;
};

export type SuggestionContext = {
  id: string;
  text: string;
  category: string;
  rationale: string;
  confidence: number;
  status: string;
  suggested_by: string;
  created_at: string;
};

export type ActiveSessionContext = {
  id: string;
