/* ── Auth Guard ── */

.auth-guard-loading {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100vh;
  background: var(--background);
  color: var(--muted-foreground);
}

/* ── Sign-In Page ── */

.sign-in-page {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  background: var(--background);
  padding: 1rem;
}

.sign-in-card {
  width: 100%;
  max-width: 380px;
  background: var(--card);
  border: 1px solid var(--border);
  padding: 2rem;
}

.sign-in-title {
  margin: 0 0 0.25rem;
  font-size: 1.5rem;
  font-weight: 600;
  color: var(--card-foreground);
}

.sign-in-subtitle {
  margin: 0 0 1.5rem;
  color: var(--muted-foreground);
  font-size: 0.875rem;
}

.sign-in-loading {
  color: var(--muted-foreground);
  text-align: center;
}

.sign-in-form {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.sign-in-input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  background: var(--background);
  border: 1px solid var(--input);
  color: var(--foreground);
  font-family: inherit;
  font-size: 0.875rem;
}

.sign-in-input:focus {
  outline: none;
  border-color: var(--ring);
}

.sign-in-error {
  margin: 0;
  color: var(--destructive);
  font-size: 0.8125rem;
}

.sign-in-button {
  width: 100%;
  padding: 0.5rem;
  background: var(--ring);
  border: 1px solid transparent;
  color: var(--foreground);
  font-family: inherit;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
}

.sign-in-button:hover {
  opacity: 0.9;
}

.sign-in-button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.sign-in-github {
  background: var(--muted);
}

.sign-in-divider {
  display: flex;
  align-items: center;
  gap: 0.75rem;
